<script setup lang="ts">
const devicesApi=useAttendanceDevices(); const workspace=useWorkspace(); const feedback=useUiFeedback(); const loading=ref(false); const devices=ref<any[]>([]); const tokenResult=ref<any|null>(null); const form=reactive<any>({deviceName:'Front Desk Tablet', deviceType:'WebKiosk', appVersion:'4.10.5', notes:''})
async function refresh(){ loading.value=true; try{ devices.value=await devicesApi.list() }catch(e:any){ feedback.fromError('Kiosk devices refresh failed',e) } finally{ loading.value=false } }
async function register(){ tokenResult.value=await devicesApi.register({...form, companyId:workspace.companyId.value, storeGroupId:workspace.storeGroupId.value, storeId:workspace.storeId.value}); feedback.success('Kiosk device registered','Copy token now. It is shown only once.'); await refresh() }
async function revoke(id:string){ await devicesApi.revoke(id); await refresh() }
onMounted(refresh)
</script>
<template><AppShell title="Kiosk Devices" @refresh="refresh"><section class="space-y-5"><UiModulePageHeader title="Kiosk Devices" description="Register store-locked attendance kiosk devices. Device token is shown only once." icon="i-lucide-tablet-smartphone"><template #actions><UButton label="Refresh" :loading="loading" @click="refresh"/></template></UiModulePageHeader><UCard><div class="grid gap-3 md:grid-cols-4"><UInput v-model="form.deviceName" placeholder="Device name"/><UInput v-model="form.deviceType" placeholder="Type"/><UInput v-model="form.notes" placeholder="Notes"/><UButton label="Register Device" @click="register"/></div><UAlert v-if="tokenResult" class="mt-3" color="warning" title="Copy device token now" :description="`Device ${tokenResult.deviceCode} token: ${tokenResult.deviceToken}`"/></UCard><div class="grid gap-3 md:grid-cols-2 xl:grid-cols-3"><AttendanceDeviceCard v-for="device in devices" :key="device.id" :device="device"/><UButton v-for="device in devices.filter(d=>d.status==='Active')" :key="`${device.id}-revoke`" color="error" variant="subtle" :label="`Revoke ${device.deviceCode}`" @click="revoke(device.id)"/></div></section></AppShell></template>
